import math
from typing import Optional

# class TreeNode:
#     def __init__(self, val=0, left=None, right=None):
#         self.val = val; self.left = left; self.right = right

class Solution:
    def largestBSTSubtree(self, root: Optional['TreeNode']) -> int:
        return self._dfs(root)[2]

    def _dfs(self, node: Optional['TreeNode']) -> tuple[int, int, int]:
        # Returns (min_val, max_val, largest_bst_size)
        if node is None:
            return math.inf, -math.inf, 0

        left_min, left_max, left_size = self._dfs(node.left)
        right_min, right_max, right_size = self._dfs(node.right)

        if node.val > left_max and node.val < right_min:
            return (
                min(left_min, node.val),
                max(right_max, node.val),
                left_size + right_size + 1,
            )

        return -math.inf, math.inf, max(left_size, right_size)
